// В консоли браузера выполните этот тест
async function testAuth() {
  console.log('=== Начало теста ===');
  console.log('Текущие cookies:', document.cookie || 'пусто');

  // 1. Логинимся
  console.log('\n1. Отправляем запрос на логин...');
  const loginResponse = await fetch('http://localhost:5000/login', {
    method: 'POST',
    credentials: 'include',  // ВАЖНО!
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      username: 'admin',     // ваше тестовое имя
      password: 'password'   // ваш тестовый пароль
    })
  });

  console.log('Login статус:', loginResponse.status);
  console.log('Login заголовки:');
  for (let [key, value] of loginResponse.headers.entries()) {
    console.log(`  ${key}: ${value}`);
  }

  const loginData = await loginResponse.json();
  console.log('Login ответ:', loginData);

  // 2. Проверяем cookies после логина
  console.log('\n2. Cookies после логина:', document.cookie || 'пусто');

  // 3. Запрашиваем защищенный endpoint
  console.log('\n3. Запрашиваем /api/table...');
  const tableResponse = await fetch('http://localhost:5000/api/table', {
    method: 'GET',
    credentials: 'include',  // ВАЖНО!
    headers: {
      'Accept': 'application/json',
    }
  });

  console.log('Table статус:', tableResponse.status);
  console.log('Table заголовки:');
  for (let [key, value] of tableResponse.headers.entries()) {
    console.log(`  ${key}: ${value}`);
  }

  if (tableResponse.ok) {
    const tableData = await tableResponse.json();
    console.log('Table данные:', tableData);
  } else {
    const errorText = await tableResponse.text();
    console.log('Table ошибка:', errorText);
  }

  console.log('\n=== Конец теста ===');
}

// Запустите тест
testAuth().catch(console.error);
